def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(7, 0, -1):
                for b in range(1, a + 5):
                    term1 = ((ratio - a) ** 6) / (a * b * 1.1 + 2)
                    term2 = np.sin(ratio * b / (a + 2))
                    term3 = np.power(np.cos(ratio * a / (b + 0.5)), 2)
                    priority += term1 * term2 * term3
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 1.7
            if bin_cap < item * 0.9:
                priority += np.sqrt(item * bin_cap) * 6
        elif 5 < ratio <= 8:
            acc = 0
            for c in range(2, int(np.ceil(ratio)) + 5):
                for d in range(1, c + 4):
                    val = ((ratio - c) ** 4) * np.cos(ratio * d) / (d + 0.7)
                    acc += np.tanh(val) * 1.5
            priority = acc + np.log(ratio) * 12 - np.tanh(ratio - 5) * 2.5
            if bin_cap > item * 2:
                priority -= np.exp(-2 * ratio) * 5
        elif 2 <= ratio <= 5:
            summ = 0
            for e in range(1, 15):
                summ += ((ratio - 2) ** e) / (e * 2.0) * np.sin(e * ratio)
            priority = (summ * np.cos(6 * ratio)) - np.log(ratio) * 7 + np.tanh(3 * (5 - ratio)) * 2
            if i % 2 == 0:
                priority += np.sin(ratio * i * 0.9) * 1.1
            else:
                priority -= np.cos(ratio * i * 0.9) * 1.1
        elif 1 <= ratio < 2:
            s = 0
            for f in range(1, 12):
                s += ((2 - ratio) ** f) / (f ** 1.8 + 0.3) * np.cos(f * ratio * 1.3)
            if bin_cap < item * 1.2:
                penalty = np.log1p(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(18 * ratio) * 3.2
            priority = s + penalty + np.exp(-2.0 / (ratio + 0.1))
            for g in range(1, 6):
                priority += np.sin(g * ratio * i) * ((ratio - 1) ** g) / (g + 0.3)
            if int(item * 2.3) % 5 == 0:
                priority *= 1.4
            else:
                priority /= 1.4
        elif 0.5 <= ratio < 1:
            s = 0
            for h in range(1, 18):
                s += ((1 - ratio) ** h) / (h * 5) * np.cos(h * item * 1.1)
            priority = s
            mod_cond = (i + int(item * 2.2)) % 5
            if mod_cond == 1:
                priority *= np.log1p(bin_cap + 5) * 1.7
            elif mod_cond == 3:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            else:
                priority += np.sin(ratio * item * 2) * 0.9
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.6) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 3)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.7) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 4.2
            for l in range(1, 9):
                priority += ((0.5 - ratio) ** l) / (l * 7) * np.cos(item * l * 1.3)
        elif 0.05 <= ratio < 0.2:
            s = 0
            for m in range(1, 14):
                s += ((0.2 - ratio) ** m) / (m * 3.5) * np.sin(m * ratio * 2.5)
            priority = s + 2 / (bin_cap + 6)
            if int(item * 1.1) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for n in range(1, 11):
                priority += ((0.2 - ratio) ** n) / (n * 8) * np.cos(item * n * 1.1)
        else:
            s = 0
            for o in range(1, 13):
                s += ((0.05 - ratio) ** o) / (o * 6) * np.sin(o * item * 1.2)
            priority = s + 3 / (bin_cap + 7)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.8
            else:
                priority /= 3.8
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
            for p in range(1, 10):
                priority += ((0.05 - ratio) ** p) / (p * 9) * np.cos(item * p * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 7
        elif bin_cap > item * 3.5:
            priority -= np.exp(-4 * ratio) * 5
        for q in range(1, 6):
            mod_val = (i + q) % 4
            if mod_val == 0:
                priority += np.sin(ratio * (i + q) * 1.1) * 0.4
            elif mod_val == 1:
                priority -= np.cos(ratio * (i + q) * 0.9) * 0.4
            else:
                priority += np.sin(ratio * (i + q) * 0.7) * 0.3
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.7
        elif i % 3 == 0:
            priority -= np.cos(ratio * i * 1.2) * 0.7
        else:
            priority += np.sin(ratio * i * 0.8) * 0.5
        priorities[i] = priority
    return priorities
